import React from 'react';
import { LayoutDirection as CarbonLayoutDirection } from '@carbon/react';

const LayoutDirection = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonLayoutDirection
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonLayoutDirection>
    );
};

LayoutDirection.defaultProps = {
    className: ''
};

export default LayoutDirection;
